import { index, jsonb, pgTable, text, timestamp, uuid } from "drizzle-orm/pg-core";

export const usageMetering = pgTable(
  "usage_metering",
  {
    id: uuid("id").primaryKey().defaultRandom(),
    ownerId: text("owner_id"),
    organizationId: text("organization_id"),
    key: text("key").notNull(),
    title: text("title").notNull(),
    status: text("status").notNull().default("active"),
    metadata: jsonb("metadata").$type<Record<string, unknown>>().notNull().default({}),
    createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
    updatedAt: timestamp("updated_at", { withTimezone: true }).defaultNow().notNull(),
  },
  (item) => [
    index("usage_metering_owner_idx").on(item.ownerId),
    index("usage_metering_organization_idx").on(item.organizationId),
  ]
);

export type UsageMeteringItem = {
  key: string;
  title: string;
  status?: "active" | "draft" | "archived";
  metadata?: Record<string, unknown>;
};

export function createUsageMeteringItem(item: UsageMeteringItem) {
  return {
    key: item.key,
    title: item.title,
    status: item.status ?? "active",
    metadata: item.metadata ?? {},
  };
}

export const usageMeteringChecklist = [
  "Confirm ownership boundaries",
  "Wire persistence or provider adapter",
  "Add audit events for sensitive changes",
] as const;

const items = [
  { title: "Configure", description: "Set ownership, defaults, and permissions." },
  { title: "Operate", description: "Review status, recent activity, and unresolved work." },
  { title: "Verify", description: "Run the checklist before enabling this module in production." },
];

export default function UsageMeteringPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Usage Metering</h1>
        <p className="text-muted-foreground">Usage event capture, aggregation helpers, and billing-ready usage UI.</p>
      </div>
      <div className="grid gap-3 md:grid-cols-3">
        {items.map((item) => (
          <section key={item.title} className="rounded-lg border p-4">
            <h2 className="font-medium">{item.title}</h2>
            <p className="text-sm text-muted-foreground">{item.description}</p>
          </section>
        ))}
      </div>
    </main>
  );
}
